Here's an interactive HTML document that generates a perfect maze and deploys 24 bots using a Tremaux-inspired exploration algorithm to find the exit, all within a self-contained page.
```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Maze Explorer - 24 Bots</title>
    <style>
        :root {
            --bg: #0f0f1a;
            --panel-bg: #1a1a2e;
            --text: #e0e0e0;
            --accent: #4cc9f0;
            --accent2: #f72585;
            --button-bg: #2d2d44;
            --button-hover: #3d3d5c;
            --border: #333355;
        }

        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            background: var(--bg);
            display: flex;
            justify-content: center;
            align-items: center;
            min-height: 100vh;
            font-family: 'Segoe UI', 'Consolas', 'Monaco', monospace;
            color: var(--text);
            user-select: none;
            -webkit-user-select: none;
            flex-direction: column;
            gap: 16px;
            padding: 20px;
        }

        #maze {
            background: #1a1a2a;
            border-radius: 12px;
            padding: 12px;
            box-shadow: 0 8px 32px rgba(0, 0, 0, 0.5), 0 0 0 2px var(--border);
            display: flex;
            justify-content: center;
            align-items: center;
        }

        canvas {
            display: block;
            border-radius: 6px;
            image-rendering: auto;
        }

        #info-panel {
            display: flex;
            gap: 20px;
            align-items: center;
            background: var(--panel-bg);
            padding: 12px 24px;
            border-radius: 10px;
            box-shadow: 0 4px 16px rgba(0, 0, 0, 0.4);
            border: 1px solid var(--border);
            flex-wrap: wrap;
            justify-content: center;
        }

        .stat {
            display: flex;
            align-items: center;
            gap: 8px;
            font-size: 15px;
            font-weight: 500;
            letter-spacing: 0.3px;
        }

        .stat-label {
            color: #aaa;
            text-transform: uppercase;
            font-size: 11px;
            letter-spacing: 0.5px;
        }

        #completed {
            color: #4cc9f0;
            font-weight: 700;
            font-size: 18px;
            min-width: 36px;
            text-align: center;
        }

        #timer {
            color: #f72585;
            font-weight: 700;
            font-size: 18px;
            min-width: 50px;
            text-align: center;
            font-variant-numeric: tabular-nums;
            font-family: 'Consolas', 'Monaco', 'Courier New', monospace;
        }

        #reset {
            background: var(--button-bg);
            color: var(--text);
            border: 2px solid var(--border);
            padding: 10px 20px;
            border-radius: 8px;
            cursor: pointer;
            font-size: 14px;
            font-weight: 600;
            letter-spacing: 0.5px;
            transition: all 0.2s ease;
            text-transform: uppercase;
        }

        #reset:hover {
            background: var(--button-hover);
            border-color: #5555aa;
            box-shadow: 0 0 16px rgba(100, 100, 255, 0.25);
        }

        #reset:active {
            transform: scale(0.96);
            background: #3a3a5a;
        }

        #speed-control {
            display: flex;
            align-items: center;
            gap: 6px;
            font-size: 12px;
            color: #aaa;
        }

        #speed-slider {
            width: 80px;
            accent-color: #4cc9f0;
        }

        .legend {
            display: flex;
            gap: 14px;
            flex-wrap: wrap;
            justify-content: center;
            font-size: 11px;
            color: #999;
        }
        .legend span {
            display: flex;
            align-items: center;
            gap: 5px;
        }
        .legend-dot {
            width: 10px;
            height: 10px;
            border-radius: 50%;
            display: inline-block;
        }
    </style>
</head>
<body>
    <div id="maze">
        <canvas id="maze-canvas"></canvas>
    </div>
    <div id="info-panel">
        <div class="stat">
            <span class="stat-label">Completed</span>
            <span id="completed">0</span>
            <span class="stat-label">/ 24</span>
        </div>
        <div class="stat">
            <span class="stat-label">Timer</span>
            <span id="timer">0</span>
        </div>
        <div id="speed-control">
            <span>Ticks/sec</span>
            <input type="range" id="speed-slider" min="1" max="60" value="15" step="1">
            <span id="speed-label">15</span>
        </div>
        <button id="reset">⟳ Reset</button>
    </div>
    <div class="legend">
        <span><span class="legend-dot" style="background:#4cc9f0;"></span> Spawn</span>
        <span><span class="legend-dot" style="background:#2ecc71;"></span> Exit</span>
        <span><span class="legend-dot" style="background:#f72585;"></span> Bot (searching)</span>
        <span><span class="legend-dot" style="background:#ffd700;"></span> Bot (finished)</span>
    </div>

    <script>
        (function() {
            // ───────────────────────────────────────
            // SEEDED PRNG (mulberry32)
            // ───────────────────────────────────────
            function createPRNG(seed) {
                let s = seed | 0;
                return function() {
                    s = (s + 0x6D2B79F5) | 0;
                    let t = Math.imul(s ^ (s >>> 15), 1 | s);
                    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
                    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
                };
            }

            // ───────────────────────────────────────
            // CONFIGURATION
            // ───────────────────────────────────────
            const ROWS = 20;
            const COLS = 20;
            const NUM_BOTS = 24;
            const CANVAS_SIZE = 620;
            const CELL_SIZE = Math.floor(CANVAS_SIZE / Math.max(ROWS, COLS));
            const WALL_THICKNESS = 2;
            const BOT_RADIUS = Math.max(3, Math.floor(CELL_SIZE * 0.28));
            const MAX_TICKS = 20000;

            const SPAWN = { r: 0, c: 0 };
            const EXIT = { r: ROWS - 1, c: COLS - 1 };

            // ───────────────────────────────────────
            // DIRECTION UTILITIES
            // ───────────────────────────────────────
            const DIRS = ['n', 'e', 's', 'w'];
            const DIR_VECTORS = {
                n: { dr: -1, dc: 0 },
                e: { dr: 0, dc: 1 },
                s: { dr: 1, dc: 0 },
                w: { dr: 0, dc: -1 },
            };
            const OPPOSITE = { n: 's', e: 'w', s: 'n', w: 'e' };

            function getNeighbor(r, c, dir) {
                const v = DIR_VECTORS[dir];
                return { r: r + v.dr, c: c + v.dc };
            }

            function passageKey(r1, c1, r2, c2) {
                if (r1 < r2 || (r1 === r2 && c1 < c2)) {
                    return `${r1},${c1}-${r2},${c2}`;
                }
                return `${r2},${c2}-${r1},${c1}`;
            }

            // ───────────────────────────────────────
            // MAZE GENERATION (recursive backtracking)
            // ───────────────────────────────────────
            function generateMaze(rows, cols, prng) {
                // Initialize all walls present
                const walls = [];
                for (let r = 0; r < rows; r++) {
                    walls[r] = [];
                    for (let c = 0; c < cols; c++) {
                        walls[r][c] = { n: true, e: true, s: true, w: true };
                    }
                }

                const visited = new Set();
                const stack = [];

                function visit(r, c) {
                    visited.add(`${r},${c}`);
                    const directions = shuffleArray([...DIRS], prng);
                    for (const dir of directions) {
                        const nr = r + DIR_VECTORS[dir].dr;
                        const nc = c + DIR_VECTORS[dir].dc;
                        if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && !visited.has(`${nr},${nc}`)) {
                            // Remove wall between current and neighbor
                            walls[r][c][dir] = false;
                            walls[nr][nc][OPPOSITE[dir]] = false;
                            stack.push({ r, c });
                            visit(nr, nc);
                        }
                    }
                    if (stack.length > 0) {
                        const prev = stack.pop();
                        // continue from the previous cell (implicit in recursion)
                        stack.push(prev);
                    }
                }

                // Actually, use iterative approach for reliability
                function iterativeGenerate(startR, startC) {
                    const stack = [{ r: startR, c: startC }];
                    visited.add(`${startR},${startC}`);
                    while (stack.length > 0) {
                        const current = stack[stack.length - 1];
                        const { r, c } = current;
                        const dirs = shuffleArray([...DIRS], prng);
                        let found = false;
                        for (const dir of dirs) {
                            const nr = r + DIR_VECTORS[dir].dr;
                            const nc = c + DIR_VECTORS[dir].dc;
                            if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && !visited.has(`${nr},${nc}`)) {
                                walls[r][c][dir] = false;
                                walls[nr][nc][OPPOSITE[dir]] = false;
                                visited.add(`${nr},${nc}`);
                                stack.push({ r: nr, c: nc });
                                found = true;
                                break;
                            }
                        }
                        if (!found) {
                            stack.pop();
                        }
                    }
                }

                iterativeGenerate(0, 0);
                return walls;
            }

            function shuffleArray(arr, prng) {
                const result = [...arr];
                for (let i = result.length - 1; i > 0; i--) {
                    const j = Math.floor(prng() * (i + 1));
                    [result[i], result[j]] = [result[j], result[i]];
                }
                return result;
            }

            // ───────────────────────────────────────
            // BOT CLASS
            // ───────────────────────────────────────
            class Bot {
                constructor(id, spawnR, spawnC, prefOrder) {
                    this.id = id;
                    this.pos = { r: spawnR, c: spawnC };
                    this.prevPos = { r: spawnR, c: spawnC };
                    this.path = [{ r: spawnR, c: spawnC }];
                    this.deadEnds = [];
                    this.finishTick = null;
                    this.moveProgress = 1; // 0 to 1 for animation
                    this.prefOrder = prefOrder;
                    // Memory: map from "r,c" string to { walls, explored, entranceDir }
                    this.memory = {};
                    this.traversalCount = {};
                    this.pendingEntranceDir = null;
                    // Initialize memory for spawn cell
                    this._initCellMemory(spawnR, spawnC, null);
                }

                _initCellMemory(r, c, entranceDir) {
                    const key = `${r},${c}`;
                    if (!this.memory[key]) {
                        this.memory[key] = {
                            walls: null, // Will be set when walls are discovered
                            explored: { n: false, e: false, s: false, w: false },
                            entranceDir: entranceDir,
                        };
                    }
                }

                discoverWalls(r, c, walls) {
                    const key = `${r},${c}`;
                    if (this.memory[key] && this.memory[key].walls === null) {
                        this.memory[key].walls = {
                            n: walls[r][c].n,
                            e: walls[r][c].e,
                            s: walls[r][c].s,
                            w: walls[r][c].w,
                        };
                    }
                }

                getCellMemory(r, c) {
                    const key = `${r},${c}`;
                    return this.memory[key] || null;
                }

                hasVisited(r, c) {
                    const key = `${r},${c}`;
                    return !!this.memory[key] && this.memory[key].walls !== null;
                }

                isAtExit() {
                    return this.pos.r === EXIT.r && this.pos.c === EXIT.c;
                }

                decideMove() {
                    const r = this.pos.r;
                    const c = this.pos.c;
                    const cellMem = this.getCellMemory(r, c);
                    if (!cellMem || cellMem.walls === null) return null;

                    const candidates = [];

                    for (const dir of DIRS) {
                        if (!cellMem.walls[dir]) {
                            const neighbor = getNeighbor(r, c, dir);
                            const pk = passageKey(r, c, neighbor.r, neighbor.c);
                            const count = this.traversalCount[pk] || 0;
                            if (count < 2) {
                                candidates.push({
                                    dir,
                                    nr: neighbor.r,
                                    nc: neighbor.c,
                                    pk,
                                    isUnvisited: !this.hasVisited(neighbor.r, neighbor.c),
                                    count,
                                });
                            }
                        }
                    }

                    if (candidates.length === 0) return null;

                    const unvisited = candidates.filter(c => c.isUnvisited);
                    const visited = candidates.filter(c => !c.isUnvisited);

                    let chosen = null;
                    let isBacktracking = false;

                    if (unvisited.length > 0) {
                        // Pick based on preference order
                        for (const prefDir of this.prefOrder) {
                            const match = unvisited.find(c => c.dir === prefDir);
                            if (match) {
                                chosen = match;
                                break;
                            }
                        }
                    } else if (visited.length > 0) {
                        isBacktracking = true;
                        const entranceDir = cellMem.entranceDir;
                        if (entranceDir) {
                            const match = visited.find(c => c.dir === entranceDir && c.count < 2);
                            if (match) {
                                chosen = match;
                            }
                        }
                        if (!chosen) {
                            // Pick first visited with count < 2
                            chosen = visited[0];
                        }
                    }

                    return { chosen, isBacktracking, cellMem, candidates };
                }

                markDeadEndIfNeeded(r, c, cellMem) {
                    // Check if all non-wall passages have been traversed at least once
                    if (!cellMem || cellMem.walls === null) return;
                    let allExplored = true;
                    for (const dir of DIRS) {
                        if (!cellMem.walls[dir]) {
                            const neighbor = getNeighbor(r, c, dir);
                            const pk = passageKey(r, c, neighbor.r, neighbor.c);
                            if ((this.traversalCount[pk] || 0) === 0) {
                                allExplored = false;
                                break;
                            }
                        }
                    }
                    if (allExplored) {
                        const alreadyDead = this.deadEnds.some(de => de.r === r && de.c === c);
                        if (!alreadyDead) {
                            this.deadEnds.push({ r, c });
                        }
                    }
                }

                step(walls) {
                    if (this.finishTick !== null) return false; // Already finished

                    const r = this.pos.r;
                    const c = this.pos.c;

                    // Discover walls of current cell
                    this.discoverWalls(r, c, walls);

                    // Check exit
                    if (this.isAtExit()) {
                        return true; // Will set finishTick externally
                    }

                    // Decide move
                    const decision = this.decideMove();
                    if (!decision || !decision.chosen) return false;

                    const { chosen, isBacktracking, cellMem } = decision;

                    // Mark dead end if backtracking and all explored
                    if (isBacktracking) {
                        this.markDeadEndIfNeeded(r, c, cellMem);
                    }

                    // Mark explored
                    cellMem.explored[chosen.dir] = true;

                    // Increment traversal count
                    this.traversalCount[chosen.pk] = (this.traversalCount[chosen.pk] || 0) + 1;

                    // Set entrance direction for next cell
                    if (chosen.isUnvisited) {
                        this._initCellMemory(chosen.nr, chosen.nc, OPPOSITE[chosen.dir]);
                    }

                    // Update position
                    this.prevPos = { r: this.pos.r, c: this.pos.c };
                    this.pos = { r: chosen.nr, c: chosen.nc };
                    this.path.push({ r: chosen.nr, c: chosen.nc });
                    this.moveProgress = 0;

                    return false;
                }

                reset(spawnR, spawnC, prefOrder) {
                    this.pos = { r: spawnR, c: spawnC };
                    this.prevPos = { r: spawnR, c: spawnC };
                    this.path = [{ r: spawnR, c: spawnC }];
                    this.deadEnds = [];
                    this.finishTick = null;
                    this.moveProgress = 1;
                    this.prefOrder = prefOrder || this.prefOrder;
                    this.memory = {};
                    this.traversalCount = {};
                    this.pendingEntranceDir = null;
                    this._initCellMemory(spawnR, spawnC, null);
                }

                getInterpolatedPos(progress) {
                    const p = Math.max(0, Math.min(1, progress !== undefined ? progress : this
                    .moveProgress));
                    const r = this.prevPos.r + (this.pos.r - this.prevPos.r) * p;
                    const c = this.prevPos.c + (this.pos.c - this.prevPos.c) * p;
                    return { r, c };
                }
            }

            // ───────────────────────────────────────
            // GAME ENGINE
            // ───────────────────────────────────────
            class Game {
                constructor(seed) {
                    this._seed = seed;
                    this._prng = createPRNG(seed);
                    this._walls = null;
                    this._bots = [];
                    this._totalTicks = 0;
                    this._frozenElapsed = null;
                    this._frozen = false;
                    this._lastTickTime = performance.now();
                    this._tickDuration = 1000 / 15; // ~67ms at 15 ticks/sec

                    this._initMaze();
                    this._initBots();
                }

                _initMaze() {
                    this._prng = createPRNG(this._seed);
                    this._walls = generateMaze(ROWS, COLS, this._prng);
                }

                _initBots() {
                    this._bots = [];
                    const botPRNG = createPRNG(this._seed + 12345);
                    for (let i = 0; i < NUM_BOTS; i++) {
                        const prefSeed = this._seed + i * 7919;
                        const prefPRNG = createPRNG(prefSeed);
                        const prefOrder = shuffleArray([...DIRS], prefPRNG);
                        const bot = new Bot(i, SPAWN.r, SPAWN.c, prefOrder);
                        // Discover spawn walls immediately
                        bot.discoverWalls(SPAWN.r, SPAWN.c, this._walls);
                        this._bots.push(bot);
                    }
                }

                get size() {
                    return { rows: ROWS, cols: COLS };
                }
                get spawn() {
                    return { ...SPAWN };
                }
                get exit() {
                    return { ...EXIT };
                }
                get elapsed() {
                    if (this._frozen && this._frozenElapsed !== null) {
                        return this._frozenElapsed;
                    }
                    return this._totalTicks;
                }
                get bots() {
                    return this._bots;
                }

                walls(r, c) {
                    if (r < 0 || r >= ROWS || c < 0 || c >= COLS) {
                        return { n: true, e: true, s: true, w: true };
                    }
                    const w = this._walls[r][c];
                    return { n: w.n, e: w.e, s: w.s, w: w.w };
                }

                tick(n) {
                    if (this._frozen) return;
                    const ticksToProcess = Math.min(n, MAX_TICKS - this._totalTicks);
                    for (let t = 0; t < ticksToProcess; t++) {
                        if (this._frozen) break;
                        this._totalTicks++;
                        let allFinished = true;
                        for (const bot of this._bots) {
                            if (bot.finishTick !== null) continue;
                            const reachedExit = bot.step(this._walls);
                            if (reachedExit) {
                                bot.finishTick = this._totalTicks;
                            }
                            if (bot.finishTick === null) {
                                allFinished = false;
                            }
                        }
                        if (allFinished) {
                            this._frozenElapsed = this._totalTicks;
                            this._frozen = true;
                            break;
                        }
                    }
                    // Update animation timing
                    for (const bot of this._bots) {
                        if (bot.moveProgress < 1 && bot.finishTick === null) {
                            // Keep moveProgress as is for animation
                        } else if (ticksToProcess >= 1 && bot.finishTick !== null) {
                            bot.moveProgress = 1;
                        }
                    }
                    if (ticksToProcess >= 1) {
                        this._lastTickTime = performance.now();
                    }
                }

                reset(seed) {
                    if (seed !== undefined && typeof seed === 'number') {
                        this._seed = seed;
                    } else if (seed === undefined) {
                        this._seed = Math.floor(Math.random() * 2147483647);
                    }
                    this._prng = createPRNG(this._seed);
                    this._totalTicks = 0;
                    this._frozenElapsed = null;
                    this._frozen = false;
                    this._lastTickTime = performance.now();
                    this._initMaze();
                    this._initBots();
                }

                getSeed() {
                    return this._seed;
                }

                allFinished() {
                    return this._frozen;
                }
            }

            // ───────────────────────────────────────
            // RENDERER
            // ───────────────────────────────────────
            const canvas = document.getElementById('maze-canvas');
            const ctx = canvas.getContext('2d');
            canvas.width = CANVAS_SIZE;
            canvas.height = CANVAS_SIZE;

            // Pre-generate bot colors
            const BOT_COLORS = [];
            for (let i = 0; i < NUM_BOTS; i++) {
                const hue = (i * 360) / NUM_BOTS;
                BOT_COLORS.push(`hsl(${hue}, 75%, 55%)`);
            }
            const BOT_FINISHED_COLOR = '#ffd700';
            const SPAWN_COLOR = '#4cc9f0';
            const EXIT_COLOR = '#2ecc71';
            const WALL_COLOR = '#c8c8d8';
            const BG_COLOR = '#1a1a2e';
            const GRID_COLOR = '#252540';

            function drawMaze(game) {
                ctx.clearRect(0, 0, canvas.width, canvas.height);

                // Background
                ctx.fillStyle = BG_COLOR;
                ctx.fillRect(0, 0, canvas.width, canvas.height);

                // Draw subtle grid lines (cell boundaries)
                ctx.strokeStyle = GRID_COLOR;
                ctx.lineWidth = 0.5;
                for (let r = 0; r <= ROWS; r++) {
                    const y = r * CELL_SIZE;
                    ctx.beginPath();
                    ctx.moveTo(0, y);
                    ctx.lineTo(COLS * CELL_SIZE, y);
                    ctx.stroke();
                }
                for (let c = 0; c <= COLS; c++) {
                    const x = c * CELL_SIZE;
                    ctx.beginPath();
                    ctx.moveTo(x, 0);
                    ctx.lineTo(x, ROWS * CELL_SIZE);
                    ctx.stroke();
                }

                // Highlight spawn cell
                ctx.fillStyle = SPAWN_COLOR;
                ctx.globalAlpha = 0.25;
                ctx.fillRect(SPAWN.c * CELL_SIZE + 1, SPAWN.r * CELL_SIZE + 1, CELL_SIZE - 2, CELL_SIZE - 2);
                ctx.globalAlpha = 1;

                // Highlight exit cell
                ctx.fillStyle = EXIT_COLOR;
                ctx.globalAlpha = 0.3;
                ctx.fillRect(EXIT.c * CELL_SIZE + 1, EXIT.r * CELL_SIZE + 1, CELL_SIZE - 2, CELL_SIZE - 2);
                ctx.globalAlpha = 1;

                // Draw walls
                ctx.strokeStyle = WALL_COLOR;
                ctx.lineWidth = WALL_THICKNESS;
                ctx.lineCap = 'round';

                for (let r = 0; r < ROWS; r++) {
                    for (let c = 0; c < COLS; c++) {
                        const x = c * CELL_SIZE;
                        const y = r * CELL_SIZE;
                        const w = game.walls(r, c);

                        if (w.n) {
                            ctx.beginPath();
                            ctx.moveTo(x, y);
                            ctx.lineTo(x + CELL_SIZE, y);
                            ctx.stroke();
                        }
                        if (w.e) {
                            ctx.beginPath();
                            ctx.moveTo(x + CELL_SIZE, y);
                            ctx.lineTo(x + CELL_SIZE, y + CELL_SIZE);
                            ctx.stroke();
                        }
                        if (w.s) {
                            ctx.beginPath();
                            ctx.moveTo(x, y + CELL_SIZE);
                            ctx.lineTo(x + CELL_SIZE, y + CELL_SIZE);
                            ctx.stroke();
                        }
                        if (w.w) {
                            ctx.beginPath();
                            ctx.moveTo(x, y);
                            ctx.lineTo(x, y + CELL_SIZE);
                            ctx.stroke();
                        }
                    }
                }

                // Draw bots
                const now = performance.now();
                const tickProgress = Math.min(1, (now - game._lastTickTime) / game._tickDuration);

                for (let i = 0; i < game.bots.length; i++) {
                    const bot = game.bots[i];
                    const progress = bot.finishTick !== null ? 1 : Math.max(0, Math.min(1, bot.moveProgress +
                        tickProgress * (1 - bot.moveProgress) * 0.9));
                    const ipos = bot.getInterpolatedPos(progress);
                    const bx = ipos.c * CELL_SIZE + CELL_SIZE / 2;
                    const by = ipos.r * CELL_SIZE + CELL_SIZE / 2;

                    const color = bot.finishTick !== null ? BOT_FINISHED_COLOR : BOT_COLORS[i];

                    // Glow
                    ctx.fillStyle = color;
                    ctx.globalAlpha = 0.4;
                    ctx.beginPath();
                    ctx.arc(bx, by, BOT_RADIUS + 3, 0, Math.PI * 2);
                    ctx.fill();
                    ctx.globalAlpha = 1;

                    // Main dot
                    ctx.fillStyle = color;
                    ctx.beginPath();
                    ctx.arc(bx, by, BOT_RADIUS, 0, Math.PI * 2);
                    ctx.fill();

                    // Outline
                    ctx.strokeStyle = 'rgba(0,0,0,0.5)';
                    ctx.lineWidth = 1;
                    ctx.beginPath();
                    ctx.arc(bx, by, BOT_RADIUS, 0, Math.PI * 2);
                    ctx.stroke();
                }

                // Draw exit marker
                const ex = EXIT.c * CELL_SIZE + CELL_SIZE / 2;
                const ey = EXIT.r * CELL_SIZE + CELL_SIZE / 2;
                ctx.strokeStyle = EXIT_COLOR;
                ctx.lineWidth = 3;
                ctx.globalAlpha = 0.7;
                ctx.beginPath();
                ctx.arc(ex, ey, CELL_SIZE * 0.35, 0, Math.PI * 2);
                ctx.stroke();
                ctx.globalAlpha = 1;
                // Exit icon (flag/door indicator)
                ctx.fillStyle = EXIT_COLOR;
                ctx.globalAlpha = 0.8;
                ctx.beginPath();
                ctx.moveTo(ex - 5, ey - 8);
                ctx.lineTo(ex + 7, ey - 3);
                ctx.lineTo(ex - 1, ey);
                ctx.lineTo(ex - 1, ey + 8);
                ctx.lineTo(ex - 5, ey + 4);
                ctx.closePath();
                ctx.fill();
                ctx.globalAlpha = 1;
            }

            // ───────────────────────────────────────
            // UI STATE
            // ───────────────────────────────────────
            const initialSeed = Math.floor(Math.random() * 2147483647);
            const game = new Game(initialSeed);
            let animFrameId = null;
            let autoRunInterval = null;
            let tickSpeed = 15; // ticks per second

            const completedEl = document.getElementById('completed');
            const timerEl = document.getElementById('timer');
            const resetBtn = document.getElementById('reset');
            const speedSlider = document.getElementById('speed-slider');
            const speedLabel = document.getElementById('speed-label');

            function updateUI() {
                const finishedCount = game.bots.filter(b => b.finishTick !== null).length;
                completedEl.textContent = finishedCount;
                timerEl.textContent = game.elapsed;
            }

            function startAutoRun() {
                stopAutoRun();
                game._tickDuration = 1000 / tickSpeed;
                game._lastTickTime = performance.now();
                autoRunInterval = setInterval(() => {
                    if (!game.allFinished()) {
                        game.tick(1);
                        updateUI();
                    } else {
                        stopAutoRun();
                    }
                }, game._tickDuration);
            }

            function stopAutoRun() {
                if (autoRunInterval !== null) {
                    clearInterval(autoRunInterval);
                    autoRunInterval = null;
                }
            }

            function renderLoop() {
                drawMaze(game);
                updateUI();
                animFrameId = requestAnimationFrame(renderLoop);
            }

            resetBtn.addEventListener('click', () => {
                stopAutoRun();
                game.reset();
                game._lastTickTime = performance.now();
                updateUI();
                startAutoRun();
            });

            speedSlider.addEventListener('input', () => {
                tickSpeed = parseInt(speedSlider.value);
                speedLabel.textContent = tickSpeed;
                if (autoRunInterval !== null) {
                    startAutoRun();
                }
            });

            // ───────────────────────────────────────
            // EXPORT API
            // ───────────────────────────────────────
            window.game = {
                tick(n) {
                    stopAutoRun();
                    game.tick(n);
                    game._lastTickTime = performance.now();
                    // Set all bot moveProgress to 1 for snap rendering
                    for (const bot of game.bots) {
                        bot.moveProgress = 1;
                    }
                    updateUI();
                },
                reset(seed) {
                    stopAutoRun();
                    game.reset(seed);
                    game._lastTickTime = performance.now();
                    updateUI();
                },
                get elapsed() {
                    return game.elapsed;
                },
                get size() {
                    return game.size;
                },
                get spawn() {
                    return game.spawn;
                },
                get exit() {
                    return game.exit;
                },
                walls(r, c) {
                    return game.walls(r, c);
                },
                get bots() {
                    return game.bots;
                },
            };

            // ───────────────────────────────────────
            // STARTUP
            // ───────────────────────────────────────
            updateUI();
            renderLoop();
            startAutoRun();

            console.log(
                `Maze Explorer initialized: ${ROWS}×${COLS} maze with ${NUM_BOTS} bots. Seed: ${game.getSeed()}`
            );
            console.log('API available at window.game — try window.game.tick(100) or window.game.reset(42)');
        })();
    </script>
</body>
</html>
